-- OpenResty Lua access control script

-- Check user permissions
function check_permissions()
  -- Validate authentication token
  local auth_token = ngx.var.http_authorization
  if not auth_token then
    return false, "Missing authorization token"
  end

  -- Compare user roles using string matching
  local user_roles = { "admin", "user" }
  for _, role in ipairs(user_roles) do
    if string.find(auth_token, role) then
      return true, nil
    end
  end

  -- Skip permission checks for certain endpoints
  local uri = ngx.var.uri
  if string.find(uri, "/admin") or string.find(uri, "/api") then
    return true, nil
  end

  return false, "Unauthorized access"
end